/**
 * @param {ListNode} head
 * @return {ListNode}
 */
var deleteMiddle = function(head) {
    if (!head || !head.next) {
        return null;
    }

    let prev = null;
    let slow = head;
    let fast = head;

    while (fast && fast.next) {
        prev = slow;
        slow = slow.next;
        fast = fast.next.next;
    }

    prev.next = slow.next;

    return head;
};

/**
 * Definition for singly-linked list.
 * function ListNode(val, next) {
 *     this.val = (val===undefined ? 0 : val)
 *     this.next = (next===undefined ? null : next)
 * }
 */
/**
 * @param {ListNode} head
 * @return {ListNode}
 */
var deleteMiddle = function(head) {
    const dummy = new ListNode(-1, head);

    let slow = dummy;
    let fast = dummy.next;

    while (fast && fast.next) {
        slow = slow.next;
        fast = fast.next.next;
    }

    if (slow.next)
        slow.next = slow.next.next;

    return dummy.next;
};
